#include <stdio.h>
#include <stdlib.h>

int find(int* parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

void unionSet(int* parent, int* size, int x, int y) {
    int rootX = find(parent, x);
    int rootY = find(parent, y);
    if (rootX != rootY) {
        if (size[rootX] < size[rootY]) {
            parent[rootX] = rootY;
            size[rootY] += size[rootX];
        } else {
            parent[rootY] = rootX;
            size[rootX] += size[rootY];
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int* stamps = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &stamps[i]);
        }
        int* parent = (int*)malloc((N+1) * sizeof(int));
        int* size = (int*)malloc((N+1) * sizeof(int));
        for (int i = 1; i <= N; i++) {
            parent[i] = i;
            size[i] = 1;
        }
        for (int i = 0; i < M; i++) {
            int Ti, Ai, Bi;
            scanf("%d %d %d", &Ti, &Ai, &Bi);
            unionSet(parent, size, Ai, Bi);
        }
        int maxValue = 0;
        for (int i = 1; i <= N; i++) {
            maxValue = (find(parent, i) > maxValue) ? find(parent, i) : maxValue;
        }
        printf("%d\n", maxValue);
        free(stamps);
        free(parent);
        free(size);
    }
    return 0;
}

